            aes.Key = Encoding.UTF8.GetBytes(EncryptionKey);
            aes.Mode = CipherMode.ECB;
            aes.Padding = PaddingMode.PKCS7;

            var decryptedCreditCardNumber = aes.CreateDecryptor().TransformFinalBlock(Convert.FromBase64String(encryptedCreditCardNumber), 0, encryptedCreditCardNumber.Length);

            return Encoding.UTF8.GetString(decryptedCreditCardNumber);
